// HasParticipants applies the HasEdge predicate on the "participants" edge.
func HasParticipants() predicate.LotteryActivity {
	return predicate.LotteryActivity(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, ParticipantsTable, ParticipantsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasParticipantsWith applies the HasEdge predicate on the "participants" edge with a given conditions (other predicates).
func HasParticipantsWith(preds ...predicate.LotteryParticipant) predicate.LotteryActivity {
	return predicate.LotteryActivity(func(s *sql.Selector) {
		step := newParticipantsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasCoupons applies the HasEdge predicate on the "coupons" edge.
func HasCoupons() predicate.LotteryActivity {
	return predicate.LotteryActivity(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, CouponsTable, CouponsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasCouponsWith applies the HasEdge predicate on the "coupons" edge with a given conditions (other predicates).
func HasCouponsWith(preds ...predicate.LotteryCoupon) predicate.LotteryActivity {
	return predicate.LotteryActivity(func(s *sql.Selector) {
		step := newCouponsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.LotteryActivity) predicate.LotteryActivity {
	return predicate.LotteryActivity(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.LotteryActivity) predicate.LotteryActivity {
	return predicate.LotteryActivity(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.LotteryActivity) predicate.LotteryActivity {
	return predicate.LotteryActivity(sql.NotPredicates(p))
}
